// Prepare source article data for translation
const post = $input.first().json[0] || $input.first().json;

const cleanContent = (post?.content?.rendered || '')
  .replace(/<[^>]*>/g, '\n')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/\s+/g, ' ')
  .trim();

const sourceData = {
  post_id: post?.id,
  title: post?.title?.rendered,
  content: cleanContent,
  excerpt: post?.excerpt?.rendered?.replace(/<[^>]*>/g, '').trim(),
  slug: post?.slug,
  url: post?.link,
  categories: post?.categories || [],
  tags: post?.tags || [],
  featured_image: post?.featured_media,
  word_count: cleanContent.split(' ').length,
  meta_description: post?.yoast_meta?.yoast_wpseo_metadesc || '',
  focus_keyword: post?.yoast_meta?.yoast_wpseo_focuskw || ''
};

// Target languages with config
const targetLanguages = [
  { code: 'es', name: 'Spanish', country: 'Spain/LATAM', subdomain: 'es', currency: 'EUR/USD', temp: 0.7 },
  { code: 'pt-BR', name: 'Portuguese', country: 'Brazil', subdomain: 'pt', currency: 'BRL', temp: 0.7 },
  { code: 'de', name: 'German', country: 'Germany', subdomain: 'de', currency: 'EUR', temp: 0.6 },
  { code: 'fr', name: 'French', country: 'France', subdomain: 'fr', currency: 'EUR', temp: 0.7 },
  { code: 'hi', name: 'Hindi', country: 'India', subdomain: 'hi', currency: 'INR', temp: 0.8 },
  { code: 'id', name: 'Indonesian', country: 'Indonesia', subdomain: 'id', currency: 'IDR', temp: 0.8 },
  { code: 'ar', name: 'Arabic', country: 'Saudi Arabia/UAE', subdomain: 'ar', currency: 'SAR/AED', temp: 0.7 },
  { code: 'ja', name: 'Japanese', country: 'Japan', subdomain: 'ja', currency: 'JPY', temp: 0.6 }
];

return targetLanguages.map(lang => ({
  json: {
    ...sourceData,
    target_language: lang.code,
    target_name: lang.name,
    target_country: lang.country,
    target_subdomain: lang.subdomain,
    target_currency: lang.currency,
    translation_temp: lang.temp
  }
}));

// Parse translation and prepare for WordPress MultiSite or subdomain
const raw = $input.first().json.response || '';
const sourceData = $input.first().json;

let translation;
try {
  const match = raw.match(/```json\n([\s\S]*?)\n```/) || raw.match(/(\{[\s\S]*\})/);
  translation = JSON.parse(match ? (match[1] || match[0]) : raw);
} catch(e) {
  translation = {
    translated_title: sourceData.title + ' (' + sourceData.target_name + ')',
    translated_content: sourceData.content,
    translated_excerpt: sourceData.excerpt,
    parse_error: e.message
  };
}

// Build localized affiliate links
const localAffiliateNetworks = {
  'es': { primary: 'Digistore24', secondary: 'ClickBank', note: 'Spain + LATAM' },
  'pt-BR': { primary: 'Hotmart', secondary: 'Monetizze', note: 'Brazil-specific networks' },
  'de': { primary: 'Digistore24', secondary: 'CopeCart', note: 'German market leaders' },
  'fr': { primary: 'Digistore24', secondary: '1TPE', note: 'French networks' },
  'hi': { primary: 'vCommission', secondary: 'AdmitAd', note: 'Indian networks' },
  'id': { primary: 'Ratakan', secondary: 'Involve Asia', note: 'Indonesian networks' },
  'ar': { primary: 'Admitad', secondary: 'ArabClicks', note: 'Arabic affiliate networks' },
  'ja': { primary: 'A8.net', secondary: 'ValueCommerce', note: 'Top Japanese networks' }
};

const affiliateConfig = localAffiliateNetworks[sourceData.target_language] || 
  { primary: 'ClickBank', secondary: 'JVZoo', note: 'International fallback' };

const translatedPost = {
  source_post_id: sourceData.post_id,
  language_code: sourceData.target_language,
  language_name: sourceData.target_name,
  country: sourceData.target_country,
  subdomain: sourceData.target_subdomain,
  currency: sourceData.target_currency,

  title: translation.translated_title,
  content: translation.translated_content,
  excerpt: translation.translated_excerpt,
  meta_description: translation.translated_meta_description,
  slug: translation.translated_slug,
  keywords: translation.local_keywords || [],

  affiliate_networks: affiliateConfig,
  translation_quality: translation.translation_quality_score || 0,
  cultural_adaptations: translation.cultural_adaptations_made || [],

  wp_url: `https://${sourceData.target_subdomain}.howtogenie.com/`,
  hreflang_tag: sourceData.target_language,

  status: 'ready_to_publish',
  translated_at: new Date().toISOString()
};

return [{ json: translatedPost }];

// Add hreflang tags to ALL versions (critical for international SEO)
const allVersions = $input.all().map(item => item.json);

const hreflangLinks = allVersions.map(v => ({
  lang: v.language_code,
  url: `${v.wp_url}${v.slug}`
}));

// Also add the English original
hreflangLinks.unshift({
  lang: 'en',
  url: $('Fetch English Article').item.json[0]?.link || 'https://howtogenie.com'
});

// Generate hreflang HTML tags
const hreflangHTML = hreflangLinks
  .map(link => `<link rel="alternate" hreflang="${link.lang}" href="${link.url}" />`)
  .join('\n');

return [{
  json: {
    hreflang_tags: hreflangHTML,
    total_languages: hreflangLinks.length,
    languages: hreflangLinks.map(l => l.lang).join(', '),
    instruction: 'Add these hreflang tags to <head> of ALL language versions for proper SEO'
  }
}];
